def update_age(student, new_age):
    # Update the age in the student dictionary
    return student

import ast

def _parse_arg(raw):
    try:
        return ast.literal_eval(raw)
    except Exception:
        return raw

_inputs = []
try:
    while True:
        _inputs.append(input())
except EOFError:
    pass
student = _parse_arg(_inputs[0]) if len(_inputs) > 0 else ""
new_age = _parse_arg(_inputs[1]) if len(_inputs) > 1 else ""

print(update_age(student, new_age))

